
.popup {
  width: 100%;
  height: 100%;
  position: relative;
}
.popup-base {
  padding: 5px 15px;
  /*width: 70px;*/
  height: 50px;
  line-height:50px;
  text-align: center;
  color: #fff;
  background: #311b92;
  cursor: pointer;
}
.popup-item {
  position: absolute;
}
.center-item {
  display: -webkit-box;
  display: -ms-flexbox;
  display: flex;
  /*flex-direction: column;*/
  /*justify-content: center;*/
  -webkit-box-pack: justify;
      -ms-flex-pack: justify;
          justify-content: space-between;
  width: 100%;
  height: auto;
  border: 1px solid #311b92;
  position: absolute;
  top: 50%;
  margin-top: -45px;
}
.center-item div {
}
.mg-10 {
  margin-left: 10px;
}
.leftTop {
  top: 0;
  left: 0;
}
.rightTop {
  top: 0;
  right: 0;
}
.center {
  top: 50%;
  left: 50%;
  margin-top: -25px;
  margin-left: -40px;
}
.leftBottom{
  bottom: 0;
  left: 0;
}
.rightBottom{
  bottom: 0;
  right: 0;
}



